`,xC=[{key:"home",title:["Приветствую тебя, Странница!","Я — Вета, твой проводник в пространстве предсказаний."],text:["Я помогу тебе открыть все возможности этого приложения.","На <strong>Главной</strong> странице ты сможешь получить персональный прогноз на год, посмотреть, какие энергии несёт Луна сегодня, а также получить персональный совет от карт.","Нажав на свой аватар, ты сможешь редактировать профиль, а пополнить баланс можно коснувшись значка вет."],image:vWe,showTitle:!0},{key:"spreads",text:["На странице <strong>Расклады</strong> собраны персональные расклады для тебя, друзей и отношений.","Открой тайны своей даты рождения, узнай, какие энергии ведут тебя по жизни, и какие уроки приготовила судьба. Ба Цзы раскроет стихии, управляющие твоим путём, а Аркан рождения подскажет твои глубинные таланты и предназначение.","Хочешь понять совместимость с партнёром или узнать, что связывает тебя с близкими? В Раскладах ты найдёшь ответы и советы для гармонии в отношениях и в себе."],image:JF},{key:"oracle",text:["Задай <strong>Оракулу</strong> любой вопрос — о будущем, отношениях, работе или самом сокровенном.","Он выслушает, поддержит и поможет найти ответы на то, что важно для тебя.","Оракул всегда рядом, чтобы прояснить твои сомнения, напомнить о твоей внутренней силе и указать новые пути."],image:yWe},{key:"friends",text:["На странице <strong>Друзья</strong> ты можешь собирать свой круг друзей.","Добавляй близких сам или находи их среди контактов в Telegram.","С помощью раздела Друзья ты сможешь делать расклады не только для себя, но и узнавать совместимость, внутренний мир и предназначение тех, кто тебе дорог."],image:bWe},{key:"history",text:["На странице <strong>История</strong> ты всегда найдёшь то, что уже открыла вместе с VETA.","Во вкладке Расклады сохраняются все твои предсказания — можно возвращаться к ним, чтобы вспомнить детали и важные мысли.","Во вкладке Транзакции отображаются все списания и пополнения вет — так тебе будет удобно видеть историю монет и помнить, где ты их применяла."],image:JF}],rp=()=>{var h;const[e,t]=g.useState(0),[n,r]=g.useState(null),i=yt(),o=()=>t(m=>Math.min(m+1,xC.length-1)),a=()=>t(m=>Math.max(m-1,0)),l=()=>i(pe.Home),c=m=>{r(m.changedTouches[0].clientX)},d=m=>{if(n==null)return;const v=m.changedTouches[0].clientX-n;Math.abs(v)>30&&(v<0?o:a)(),r(null)},f=xC[e];return s.jsx(wWe,{children:s.jsxs(SWe,{onTouchStart:c,onTouchEnd:d,children:[s.jsx(_We,{src:f.image,alt:""}),s.jsx(kWe,{onClick:l,"aria-label":"Закрыть",children:s.jsx(vH,{})}),s.jsx(CWe,{children:f.showTitle?s.jsxs(s.Fragment,{children:[(h=f.title)==null?void 0:h.map((m,v)=>s.jsx(jWe,{children:m},v)),f.text.map((m,v)=>s.jsx(eN,{dangerouslySetInnerHTML:{__html:m}},v))]}):f.text.map((m,v)=>s.jsx(eN,{dangerouslySetInnerHTML:{__html:m}},v))}),s.jsx(PWe,{children:xC.map((m,v)=>s.jsx(EWe,{onClick:()=>t(v),$active:v===e,children:s.jsx(xWe,{})},v))})]})})},Zu=S.div`
